import React, { useState } from "react";

function CompareModels() {
  const [result, setResult] = useState(null);

  const sampleData = Array.from({ length: 2000 }, () => [
    Math.random(),
    Math.random(),
    Math.random()
  ]);

  const runComparison = async () => {
    try {
      const res = await fetch("http://127.0.0.1:5000/compare", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({ data: sampleData })
      });

      const data = await res.json();
      console.log(data);
      setResult(data);

    } catch (error) {
      console.error("Error:", error);
    }
  };

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>
      <h2>Model Comparison</h2>

      <button onClick={runComparison}>
        Compare OCSVM vs Isolation Forest
      </button>

      {result && !result.error && (
        <div style={{ marginTop: "20px" }}>

          <h3>OCSVM</h3>
          <p>Precision: {result.ocsvm["1"]?.precision?.toFixed(2) || "0.00"}</p>
          <p>Recall: {result.ocsvm["1"]?.recall?.toFixed(2) || "0.00"}</p>
          <p>F1-score: {result.ocsvm["1"]?.["f1-score"]?.toFixed(2) || "0.00"}</p>

          <h3>Isolation Forest</h3>
          <p>Precision: {result.isolation_forest["1"]?.precision?.toFixed(2) || "0.00"}</p>
          <p>Recall: {result.isolation_forest["1"]?.recall?.toFixed(2) || "0.00"}</p>
          <p>F1-score: {result.isolation_forest["1"]?.["f1-score"]?.toFixed(2) || "0.00"}</p>

        </div>
      )}

      {result && result.error && (
        <p style={{ color: "red" }}>
          Error: {result.error}
        </p>
      )}
    </div>
  );
}

export default CompareModels;
